"""stl_validator_improved.py — Improved STL validation tool.

Reads an ASCII STL file and reports triangle count, surface area, and validity.

Fixes the hidden failure mode in the provided validator:
- Checks whether declared face normals are consistent with the normal
  implied by vertex winding order.
- Also checks for degenerate triangles (zero area).
- Also checks for duplicate faces.
"""
import json
import math
import sys


def _cross(a, b):
    return (
        a[1] * b[2] - a[2] * b[1],
        a[2] * b[0] - a[0] * b[2],
        a[0] * b[1] - a[1] * b[0],
    )


def _sub(a, b):
    return (a[0] - b[0], a[1] - b[1], a[2] - b[2])


def _dot(a, b):
    return a[0] * b[0] + a[1] * b[1] + a[2] * b[2]


def _magnitude(v):
    return math.sqrt(v[0] ** 2 + v[1] ** 2 + v[2] ** 2)


def _normalize(v):
    mag = _magnitude(v)
    if mag == 0:
        return (0.0, 0.0, 0.0)
    return (v[0] / mag, v[1] / mag, v[2] / mag)


def _triangle_area(v1, v2, v3):
    return 0.5 * _magnitude(_cross(_sub(v2, v1), _sub(v3, v1)))


def parse_stl(path: str) -> dict:
    issues = []
    triangles = []  # list of (declared_normal, [v1, v2, v3])

    with open(path, "r", errors="replace") as fh:
        lines = fh.readlines()

    i = 0
    while i < len(lines):
        line = lines[i].strip()

        if line.startswith("facet normal"):
            parts = line.split()
            try:
                declared_normal = (float(parts[2]), float(parts[3]), float(parts[4]))
            except (IndexError, ValueError):
                issues.append(f"Malformed facet normal at line {i + 1}")
                i += 1
                continue

            vertices = []
            i += 1
            if i < len(lines) and lines[i].strip() == "outer loop":
                i += 1
                for _ in range(3):
                    if i < len(lines):
                        vline = lines[i].strip()
                        if vline.startswith("vertex"):
                            vparts = vline.split()
                            try:
                                vertices.append(
                                    (float(vparts[1]), float(vparts[2]), float(vparts[3]))
                                )
                            except (IndexError, ValueError):
                                issues.append(f"Malformed vertex at line {i + 1}")
                        i += 1

            if len(vertices) == 3:
                triangles.append((declared_normal, vertices))
            else:
                issues.append(f"Incomplete triangle near line {i + 1}")
            continue

        i += 1

    if not triangles:
        issues.append("No valid faces found")

    # Manifold check: every edge must be shared by exactly 2 triangles.
    edge_count: dict = {}
    for _, verts in triangles:
        rounded = [tuple(round(x, 6) for x in v) for v in verts]
        for j in range(3):
            edge = tuple(sorted([rounded[j], rounded[(j + 1) % 3]]))
            edge_count[edge] = edge_count.get(edge, 0) + 1

    open_edges = sum(1 for cnt in edge_count.values() if cnt == 1)
    if open_edges > 0:
        issues.append(f"Mesh has {open_edges} open edge(s) — not a closed solid")

    # Normal consistency check (FIX for hidden failure mode).
    inverted_normals = 0
    degenerate_faces = 0
    NORMAL_ANGLE_THRESHOLD = 0.01  # radians (~0.57 degrees)
    for face_idx, (declared_normal, verts) in enumerate(triangles):
        v1, v2, v3 = verts
        cross = _cross(_sub(v2, v1), _sub(v3, v1))
        computed_mag = _magnitude(cross)

        if computed_mag < 1e-10:
            degenerate_faces += 1
            issues.append(f"Degenerate (zero-area) triangle at face {face_idx + 1}")
            continue

        computed_normal = _normalize(cross)

        # Only compare if declared normal is non-zero
        declared_mag = _magnitude(declared_normal)
        if declared_mag > 1e-10:
            declared_normalized = _normalize(declared_normal)
            dot = _dot(computed_normal, declared_normalized)
            # Clamp to [-1, 1] to avoid math domain errors
            dot = max(-1.0, min(1.0, dot))
            angle = math.acos(dot)
            if angle > NORMAL_ANGLE_THRESHOLD:
                inverted_normals += 1

    if inverted_normals > 0:
        issues.append(
            f"{inverted_normals} face(s) have normals inconsistent with vertex "
            f"winding order (possible inverted normals)"
        )

    # Duplicate face check
    face_set = set()
    duplicate_faces = 0
    for _, verts in triangles:
        rounded = tuple(sorted([tuple(round(x, 6) for x in v) for v in verts]))
        if rounded in face_set:
            duplicate_faces += 1
        else:
            face_set.add(rounded)
    if duplicate_faces > 0:
        issues.append(f"{duplicate_faces} duplicate face(s) found")

    surface_area = sum(_triangle_area(*verts) for _, verts in triangles)

    return {
        "valid": len(issues) == 0,
        "triangle_count": len(triangles),
        "surface_area": round(surface_area, 6),
        "issues": issues,
    }


if __name__ == "__main__":
    if len(sys.argv) < 2:
        print(json.dumps({"error": "usage: stl_validator_improved.py <file.stl>"}))
        sys.exit(1)
    print(json.dumps(parse_stl(sys.argv[1])))

